$$, $$e5cb06e18e84d13070d3dee251d4d3f499f96207c24673002522ddd43cc9f8cd$$, $${"A": "af1bd36610a2c185fafd53343fa9f8986b9ff5fd4e2075994b0e0a0491e752ca", "C": "74c6b792f0dea80c872084144a0d2c4a84b46c9e47ac99e8cfca7cd901846ea3", "D": "8ef988bee17430f1a2176fb6b29f86ea802775e9040979b5371913d822066c0a"}$$::jsonb, $$Budget J-Books/FY27/Remaining/RDTE_DISA_PB_2027.pdf$$, 141, $$2026-05-07T23:11:07.973865+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0208087F$$, 2026, $$Distributed Cyber Warfare Operations (DCWO) consists of a portfolio of programs and projects that conduct Research, Development, Testing and Evaluation (RDT&E)
leading to operations-ready offensive cyberspace capabilities. This includes the transition of efforts from laboratory, industry, and academia via studies, accelerated
prototyping, and technology demonstrations. DCWO effectiveness comes from balancing acquisition related RDT&E efforts in three Air Force (AF) offensive cyber
operations (OCO) mission threads (Off Network, Telephony Network, and the associated Infrastructure that propel the Off Network and Telephony Network mission
threads) across three OCO-related subsystems and technical enablers (Platforms, Access, and Cyber Weapons) that enable products, services, and systems in the
DCWO portfolio. The resulting DCWO capabilities provide cyber effects to Combatant Commanders and other offensive cyber customers to enable air superiority.

 This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program
 funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F,
 0606398F. In FY24 $1.995M was expended for civilian pay expenses in this program element, and in FY25 $2.046M is forecasted for civilian pay expenses in this
 program element.

 The FY 2026 request was reduced by $1.049 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in
 alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.”

 This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been
 fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.

